para.programlisting:
x = 1:5;
// Use lambda function
y = #(x) -> (-2*x.^4 + x.^3 - 5 * x.^2 + 6 *x -2);
p = polyfit(x, y(x), 3)

xx = linspace(1, 5, 100);
yy = polyval(p, xx);

plot(x, y(x), "b.", "thickness", 2);
plot(xx, yy, "r");

