para.programlisting:
function r = y(x)
    r = -2*x.^4 + x.^3 - 5 * x.^2 + 6 *x -2;
endfunction

x = 1:5;
p = polyfit(x, y(x), %s^3)

xx = linspace(1, 5, 100);
yy = polyval(p, xx);

plot(x, y(x), "b.", "thickness", 2);
plot(xx, yy, "r");

para.scilab:image:
function r = y(x)
    r = -2*x.^4 + x.^3 - 5 * x.^2 + 6 *x -2;
endfunction

x = 1:5;
p = polyfit(x, y(x), %s^3)

xx = linspace(1, 5, 100);
yy = polyval(p, xx);

plot(x, y(x), "b.", "thickness", 2);
plot(xx, yy, "r");

para.programlisting:
x = 0:10;
// Use lambda function
y = #(x) -> (x.^3 - 3*x + 2);

[p, S, mu] = polyfit(x, y(x), 2)

xx = linspace(0, 10, 100);
yy = polyval(p, xx, S, mu);

plot(x, y(x), "b.", "thickness", 2);
plot(xx, y(xx), "g");
plot(xx, yy, "r");

